SET NAMES utf8mb4;
SET FOREIGN_KEY_CHECKS = 0;

-- 创建数据库
CREATE DATABASE IF NOT EXISTS `agri_gateway` CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
USE `agri_gateway`;

-- ----------------------------
-- 表结构: admins
-- ----------------------------
DROP TABLE IF EXISTS `admins`;
CREATE TABLE `admins` (
  `id` int NOT NULL AUTO_INCREMENT,
  `username` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '登录用户名',
  `password` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '密码（明文，生产环境应加密）',
  `name` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT '' COMMENT '姓名',
  `role` enum('super','viewer') COLLATE utf8mb4_unicode_ci DEFAULT 'viewer' COMMENT '角色：super=超管 viewer=只读',
  `status` tinyint DEFAULT '1' COMMENT '状态：1启用 0禁用',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `username` (`username`),
  KEY `idx_username` (`username`),
  KEY `idx_role` (`role`),
  KEY `idx_status` (`status`)
) ENGINE=InnoDB AUTO_INCREMENT=4 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='管理员账号表';

-- ----------------------------
-- 表数据: admins (2 条记录)
-- ----------------------------


-- ----------------------------
-- 表结构: api_raw_records
-- ----------------------------
DROP TABLE IF EXISTS `api_raw_records`;
CREATE TABLE `api_raw_records` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `api_t_number` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'API终端号',
  `api_work_date` date NOT NULL COMMENT 'API作业日期',
  `api_work_type` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT '' COMMENT 'API作业类型代码',
  `api_work_type_name` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT '' COMMENT 'API作业类型名称',
  `api_acre` decimal(12,2) DEFAULT '0.00' COMMENT 'API作业面积',
  `api_ok_acre` decimal(12,2) DEFAULT '0.00' COMMENT 'API达标面积',
  `api_repeat_acre` decimal(12,2) DEFAULT '0.00' COMMENT 'API重复面积',
  `api_leave_acre` decimal(12,2) DEFAULT '0.00' COMMENT 'API漏耕面积',
  `api_duration` int DEFAULT '0' COMMENT 'API作业时长(秒)',
  `api_land_group` text COLLATE utf8mb4_unicode_ci COMMENT 'API GPS围栏',
  `api_county` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT '' COMMENT 'API作业地区',
  `api_plate_no` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT '' COMMENT 'API车牌号',
  `api_driver_name` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT '' COMMENT 'API机手姓名',
  `api_org_name` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT '' COMMENT 'API合作社名称',
  `current_acre` decimal(12,2) DEFAULT '0.00' COMMENT '当前作业面积',
  `current_ok_acre` decimal(12,2) DEFAULT '0.00' COMMENT '当前达标面积',
  `current_plate_no` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT '' COMMENT '当前车牌号',
  `current_driver_name` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT '' COMMENT '当前机手姓名',
  `current_org_id` int DEFAULT '0' COMMENT '当前合作社ID',
  `current_org_name` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT '' COMMENT '当前合作社名称',
  `source` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT 'yuntinan' COMMENT '数据来源',
  `status` tinyint DEFAULT '1' COMMENT '状态：1有效 0删除',
  `is_modified` tinyint DEFAULT '0' COMMENT '是否修改过',
  `remark` text COLLATE utf8mb4_unicode_ci COMMENT '备注',
  `api_received_at` datetime DEFAULT CURRENT_TIMESTAMP COMMENT 'API接收时间',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `idx_api_unique` (`api_t_number`,`api_work_date`,`api_work_type_name`,`source`),
  KEY `idx_status` (`status`),
  KEY `idx_modified` (`is_modified`),
  KEY `idx_work_date` (`api_work_date`),
  KEY `idx_org` (`current_org_id`)
) ENGINE=InnoDB AUTO_INCREMENT=32683 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='API原始数据记录表';

