-- 表结构: crawl_log
-- ----------------------------
DROP TABLE IF EXISTS `crawl_log`;
CREATE TABLE `crawl_log` (
  `id` int NOT NULL AUTO_INCREMENT,
  `source` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT 'old' COMMENT '数据源',
  `status` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT 'running' COMMENT '状态：running/success/failed',
  `total_records` int DEFAULT '0' COMMENT '总记录数',
  `new_records` int DEFAULT '0' COMMENT '新增记录数',
  `update_records` int DEFAULT '0' COMMENT '更新记录数',
  `error_msg` text COLLATE utf8mb4_unicode_ci COMMENT '错误信息',
  `started_at` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '开始时间',
  `finished_at` datetime DEFAULT NULL COMMENT '完成时间',
  PRIMARY KEY (`id`),
  KEY `idx_source_status` (`source`,`status`),
  KEY `idx_started_at` (`started_at`)
) ENGINE=InnoDB AUTO_INCREMENT=4 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='旧供应商抓取日志表';

