DROP TABLE IF EXISTS `farmers`;
CREATE TABLE `farmers` (
  `id` int NOT NULL AUTO_INCREMENT,
  `phone` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '手机号',
  `password` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '123456' COMMENT '密码',
  `name` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT '' COMMENT '姓名',
  `org_id` int DEFAULT '0' COMMENT '所属组织ID',
  `org_name` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT '' COMMENT '所属组织名称',
  `role` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT 'farmer' COMMENT '角色',
  `remark` text COLLATE utf8mb4_unicode_ci COMMENT '备注',
  `enabled` tinyint DEFAULT '1' COMMENT '是否启用',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `phone` (`phone`),
  KEY `idx_phone` (`phone`),
  KEY `idx_org` (`org_id`)
) ENGINE=InnoDB AUTO_INCREMENT=6 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='农户账号表';

