-- 表结构: imports
-- ----------------------------
DROP TABLE IF EXISTS `imports`;
CREATE TABLE `imports` (
  `id` int NOT NULL AUTO_INCREMENT,
  `file_name` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '文件名',
  `file_size` int DEFAULT '0' COMMENT '文件大小',
  `import_type` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT '' COMMENT '导入类型',
  `row_count` int DEFAULT '0' COMMENT '总行数',
  `success_count` int DEFAULT '0' COMMENT '成功数',
  `skip_count` int DEFAULT '0' COMMENT '跳过数',
  `error_count` int DEFAULT '0' COMMENT '错误数',
  `errors` text COLLATE utf8mb4_unicode_ci COMMENT '错误信息',
  `status` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT 'completed' COMMENT '状态',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='导入记录表';


-- ----------------------------
-- 表结构: machine_tracks
-- ----------------------------
DROP TABLE IF EXISTS `machine_tracks`;
CREATE TABLE `machine_tracks` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `t_number` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '终端号',
  `work_date` date NOT NULL COMMENT '作业日期',
  `track_time` datetime NOT NULL COMMENT '轨迹时间点',
  `longitude` decimal(10,6) NOT NULL COMMENT '经度',
  `latitude` decimal(10,6) NOT NULL COMMENT '纬度',
  `speed` decimal(8,2) DEFAULT '0.00' COMMENT '速度(km/h)',
  `direction` decimal(8,2) DEFAULT '0.00' COMMENT '方向角(度)',
  `altitude` decimal(10,2) DEFAULT '0.00' COMMENT '海拔(米)',
  `work_type` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT '' COMMENT '作业类型',
  `status` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT '' COMMENT '状态(在线/离线)',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_t_date` (`t_number`,`work_date`),
  KEY `idx_track_time` (`track_time`),
  KEY `idx_work_date` (`work_date`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='设备作业轨迹表';


