-- 表结构: work_records
-- ----------------------------
DROP TABLE IF EXISTS `work_records`;
CREATE TABLE `work_records` (
  `id` int NOT NULL AUTO_INCREMENT,
  `api_id` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'API原始记录ID',
  `t_number` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '终端号',
  `work_date` date DEFAULT NULL COMMENT '作业日期',
  `work_type` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT '' COMMENT '作业类型代码',
  `work_type_name` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT '' COMMENT '作业类型名称',
  `acre` decimal(12,2) DEFAULT '0.00' COMMENT '作业面积',
  `ok_acre` decimal(12,2) DEFAULT '0.00' COMMENT '达标面积',
  `repeat_acre` decimal(12,2) DEFAULT '0.00' COMMENT '重复面积',
  `leave_acre` decimal(12,2) DEFAULT '0.00' COMMENT '漏耕面积',
  `duration` int DEFAULT '0' COMMENT '作业时长(秒)',
  `org_id` int DEFAULT '0' COMMENT '所属组织ID',
  `org_name` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT '' COMMENT '所属组织名称',
  `plate_no` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT '' COMMENT '车牌号',
  `driver_name` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT '' COMMENT '驾驶员姓名',
  `land_group` text COLLATE utf8mb4_unicode_ci COMMENT 'GPS围栏多边形',
  `county` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT '' COMMENT '作业地区',
  `import_id` int DEFAULT NULL COMMENT '导入记录ID',
  `source` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT 'old' COMMENT '数据来源',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `idx_api_unique` (`api_id`,`source`),
  KEY `idx_t_number` (`t_number`),
  KEY `idx_work_date` (`work_date`),
  KEY `idx_source` (`source`),
  KEY `idx_org` (`org_id`),
  KEY `idx_county` (`county`),
  KEY `idx_work_lookup` (`t_number`,`work_date`,`work_type_name`,`source`)
) ENGINE=InnoDB AUTO_INCREMENT=5655 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='作业记录表';

